parameters.jsCode:
const response = $input.first().json;
const config = $('2. Set — Config Values').item.json;

const all = response?.data?.transcripts || [];
const cutoff = config.sevenDaysAgoMs;
const meetings = all.filter(t => (t.date || 0) >= cutoff);

if (meetings.length === 0) {
  return [{
    json: {
      hasMeetings: false,
      weekStart: config.weekStart,
      weekEnd: config.weekEnd,
      managerEmail: config.managerEmail,
      senderName: config.senderName,
      companyName: config.companyName,
      sheetId: config.sheetId,
      sheetName: config.sheetName
    }
  }];
}

const totalMeetings = meetings.length;
const totalSeconds = meetings.reduce((sum, m) => sum + (m.duration || 0), 0);
const totalMinutes = Math.round(totalSeconds / 60);
const totalHours = (totalMinutes / 60).toFixed(1);
const avgDuration = Math.round(totalMinutes / totalMeetings);

const dayCount = {};
const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
meetings.forEach(m => {
  const day = dayNames[new Date(m.date).getDay()];
  dayCount[day] = (dayCount[day] || 0) + 1;
});
const busiestDay = Object.entries(dayCount).sort((a,b) => b[1]-a[1])[0];
const busiestDayLabel = busiestDay ? busiestDay[0] + ' (' + busiestDay[1] + ' meetings)' : 'N/A';

const participantCount = {};
meetings.forEach(m => {
  (m.participants || []).forEach(p => {
    if (p && p.trim()) participantCount[p.trim()] = (participantCount[p.trim()] || 0) + 1;
  });
});
const topParticipant = Object.entries(participantCount).sort((a,b) => b[1]-a[1])[0];
const topParticipantLabel = topParticipant ? topParticipant[0] + ' (' + topParticipant[1] + ' meetings)' : 'N/A';

const longest = meetings.reduce((max, m) => (m.duration||0) > (max.duration||0) ? m : max, meetings[0]);
const longestLabel = (longest.title || 'Untitled') + ' — ' + Math.round((longest.duration||0)/60) + ' min';

const allParticipants = [...new Set(
  meetings.flatMap(m => m.participants || []).filter(p => p && p.trim())
)].join(', ');

const dailyBreakdown = {};
meetings.forEach(m => {
  const date = new Date(m.date).toLocaleDateString('en-GB', { weekday:'short', day:'2-digit', month:'short' });
  if (!dailyBreakdown[date]) dailyBreakdown[date] = { count: 0, minutes: 0, ts: m.date };
  dailyBreakdown[date].count++;
  dailyBreakdown[date].minutes += Math.round((m.duration||0)/60);
});
let dailyText = '';
Object.entries(dailyBreakdown)
  .sort((a,b) => a[1].ts - b[1].ts)
  .forEach(([day, data]) => {
    dailyText += day + ': ' + data.count + ' meeting(s), ' + data.minutes + ' min\n';
  });

let meetingList = '';
meetings
  .sort((a,b) => (b.date||0) - (a.date||0))
  .forEach((m, i) => {
    const date = new Date(m.date).toLocaleDateString('en-GB', { day:'2-digit', month:'short' });
    const dur = Math.round((m.duration||0)/60);
    meetingList += (i+1) + '. ' + date + ' — ' + (m.title||'Untitled') + ' (' + dur + ' min)\n';
  });

const loggedAt = new Date().toISOString().replace('T',' ').substring(0,16);

return [{
  json: {
    hasMeetings: true,
    weekLabel: config.weekStart + ' to ' + config.weekEnd,
    totalMeetings,
    totalHours,
    avgDuration,
    busiestDay: busiestDayLabel,
    topParticipant: topParticipantLabel,
    longestMeeting: longestLabel,
    allParticipants,
    loggedAt,
    dailyText,
    meetingList,
    totalMinutes,
    weekStart: config.weekStart,
    weekEnd: config.weekEnd,
    managerEmail: config.managerEmail,
    senderName: config.senderName,
    companyName: config.companyName,
    sheetId: config.sheetId,
    sheetName: config.sheetName
  }
}];

